/*  U1      u1_g_oXDoCANRoutStart_11FD(U1 * u1_ap_ans, const U2 u2_a_ELPSD, U2 * u2_ap_nbyte)                                        */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
U1      u1_g_oXDoCANRoutStart_11FD(U1 * u1_ap_ans, const U2 u2_a_ELPSD, U2 * u2_ap_nbyte)
{
    u1_ap_ans[OXDC_ROUT_ANS_RINF_11FD] = (U1)OXDC_11FD_RINF;

    (void)u1_g_TyDoCANDilReset((U1)TYDC_DIL_MEM_BRA, (U1)TRUE);
    vd_g_TyDoCANLogRAMReset();

    return((U1)OXDC_SAL_PROC_FIN);
}
